                                result.push(wasm.{table}.get(mem.getUint32(i, true)));
                            }}
                            return result;
                        }}
                        ",
                    )
                    .into()
                });
            }
            _ => {
                self.expose_get_object();
                self.intrinsic(ret.to_string().into(), None, {
                    format!(
                        "
                        function {ret}(ptr, len) {{
                            ptr = ptr >>> 0;
